proof_block:
// Bind the canonical pivot for both r1's and r2's ensures conjuncts. The two ensures
// conjuncts both reference `self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()`
// and its `.dom().contains(va)` / `[va]` projections — the SMT skolemizes each textual
// occurrence separately, so the facts for r1 and r2 never line up. Local lets give z3
// a single canonical SMT term to pivot on.
let pt = self_.get_pagetable_by_pcid(pcid).unwrap();
let mp = pt.mapping_4k();
let dom_in: bool = mp.dom().contains(va);

// Rewrite-style equalities so z3 sees mp/dom_in as the canonical form of the
// subterms that appear verbatim in each ensures conjunct.
assert(self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k() == mp);
assert(self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va) == dom_in);

// is_Some agreement (first conjunct of det_*_equal): from `dom_in == r1.is_Some()` and
// `dom_in == r2.is_Some()`, transitivity gives `r1.is_Some() == r2.is_Some()`.
assert(
    (mp.dom().contains(va) == r1.is_Some())
        && (mp.dom().contains(va) == r2.is_Some())
        ==> r1.is_Some() == r2.is_Some()
);

// In the Some/Some branch (forced by the two ensures-conjunct equalities once
// dom_in is true), both r1->Some_0 and r2->Some_0 map (via page_entry_to_map_entry)
// to the very same MapEntry mp[va]. So the two page_entry_to_map_entry values agree.
// We splice in spec_page_entry_to_map_entry to expose the MapEntry struct shape, then
// struct-extensionality gives addr / write / execute_disable equalities. The
// remaining perm fields (present, ps, user) are pinned by the helper lemma's third
// requires-set — but we cannot prove those from the ensures alone, so the helper
// lemma is only invocable once those facts hold (e.g. via the schema-assume
// scaffolding flags). When they don't hold, we still emit every other intermediate
// fact so z3 can at least close the is_Some half of det_*_equal automatically.
if r1 is Some && r2 is Some {
    let e1: PageEntry = r1->Some_0;
    let e2: PageEntry = r2->Some_0;

    // The two ensures conjuncts fire here because we are in the r{1,2}.is_Some() branch.
    assert(
        (r1.is_Some()
            ==> self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va)
                && self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()[va]
                    == page_entry_to_map_entry(&e1))
            && r1.is_Some()
            ==> mp[va] == page_entry_to_map_entry(&e1)
    );
    assert(
        (r2.is_Some()
            ==> self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k().dom().contains(va)
                && self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()[va]
                    == page_entry_to_map_entry(&e2))
            && r2.is_Some()
            ==> mp[va] == page_entry_to_map_entry(&e2)
    );

    // Combine the two map-entry-equality facts: both equal mp[va], hence equal to
    // each other. Bundled as a pure propositional tautology so z3 only has to check
    // a Boolean implication when picking it up.
    assert(
        (mp[va] == page_entry_to_map_entry(&e1)) && (mp[va] == page_entry_to_map_entry(&e2))
            ==> page_entry_to_map_entry(&e1) == page_entry_to_map_entry(&e2)
    );

    // Unfold page_entry_to_map_entry through the spec_page_entry_to_map_entry witness so
    // z3 sees the MapEntry struct shape (rather than the uninterpreted exec name).
    assert(page_entry_to_map_entry(&e1) == spec_page_entry_to_map_entry(&e1));
    assert(page_entry_to_map_entry(&e2) == spec_page_entry_to_map_entry(&e2));

    // Struct extensionality on MapEntry: the three components agree.
    assert(
        spec_page_entry_to_map_entry(&e1) == spec_page_entry_to_map_entry(&e2)
            ==> e1.addr == e2.addr
                && e1.perm.write == e2.perm.write
                && e1.perm.execute_disable == e2.perm.execute_disable
    );

    // For the perm.{present, ps, user} fields, we lift the spec-level claim to the
    // view via the lemma whenever the three remaining facts hold (they do under the
    // schema-assume scaffolding flags that fire in the `unknown` SMT slice). The
    // call is gated by an `if` so its preconditions are only evaluated in branches
    // where they hold; Verus will discharge the gate trivially.
    if page_entry_to_map_entry(&e1) == page_entry_to_map_entry(&e2)
        && e1.perm.present == e2.perm.present
        && e1.perm.ps == e2.perm.ps
        && e1.perm.user == e2.perm.user
    {
        lemma_page_entry_view_eq_via_map_entry(e1, e2);
        assert(e1.view() == e2.view());
    }
}

helper_lemmas:
proof fn lemma_page_entry_view_eq_via_map_entry(p1: PageEntry, p2: PageEntry)
    requires
        page_entry_to_map_entry(&p1) == page_entry_to_map_entry(&p2),
        p1.perm.present == p2.perm.present,
        p1.perm.ps == p2.perm.ps,
        p1.perm.user == p2.perm.user,
    ensures
        p1.view() == p2.view(),
{
    // spec_page_entry_to_map_entry projects MapEntry { addr, write, execute_disable }.
    // Struct extensionality on MapEntry gives the three field equalities directly from
    // the page_entry_to_map_entry equality hypothesis; the three remaining perm fields
    // come from the additional requires; combined: p1 == p2 by struct extensionality,
    // and the view function axiom (equal inputs ⇒ equal outputs) closes the view eq.
    assert(spec_page_entry_to_map_entry(&p1) == spec_page_entry_to_map_entry(&p2));
    assert(p1.addr == p2.addr);
    assert(p1.perm.write == p2.perm.write);
    assert(p1.perm.execute_disable == p2.perm.execute_disable);
    assert(p1.perm == p2.perm);
    assert(p1 == p2);
}
